from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify the main subject (airport) - typically the one with cityServed, runway, or location predicates
    main_subject = None
    for subject, triples_list in subject_map.items():
        if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel"] for p, _ in triples_list):
            main_subject = subject
            break
    if not main_subject:
        main_subject = list(subject_map.keys())[0]

    # Build a complex sentence by connecting related entities
    sentence = main_subject
    main_triples = subject_map[main_subject]

    # Handle cityServed first as it's often the primary relationship
    city_served = None
    for predicate, obj in main_triples:
        if predicate == "cityServed":
            city_served = obj
            sentence += f" serves the city of {obj}"
            break

    # Add other attributes of the main subject
    additional_info = []
    for predicate, obj in main_triples:
        if predicate == "cityServed":
            continue
        elif predicate == "location":
            additional_info.append(f"is located in {obj}")
        elif predicate == "elevationAboveTheSeaLevel":
            additional_info.append(f"has an elevation of {obj} metres above sea level")
        elif predicate == "runwayLength":
            additional_info.append(f"has a runway length of {obj} metres")
        elif predicate == "runwayName":
            additional_info.append(f"has a runway named {obj}")
        elif predicate == "operatingOrganisation":
            additional_info.append(f"is operated by {obj}")
        elif predicate == "icaoLocationIdentifier":
            additional_info.append(f"has an ICAO identifier of {obj}")
        elif predicate == "iataLocationIdentifier":
            additional_info.append(f"has an IATA identifier of {obj}")
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            additional_info.append(f"has an elevation of {obj} feet above sea level")
        elif predicate == "1stRunwayLengthFeet":
            additional_info.append(f"has a first runway length of {obj} feet")
        elif predicate == "1stRunwaySurfaceType":
            additional_info.append(f"has a first runway surface type of {obj}")
        elif predicate == "nativeName":
            additional_info.append(f"is also known as {obj}")
        elif predicate == "country":
            # If country is the same as the city's country, make a connection
            if city_served and obj.lower() in city_served.lower():
                continue  # Skip if redundant
            else:
                additional_info.append(f"is located in {obj}")
        elif predicate == "owner":
            additional_info.append(f"is owned by {obj}")

    if additional_info:
        sentence += " " + ", ".join(additional_info)

    # Look for relationships where the city_served appears as an object in other triples
    if city_served:
        for subject, triples_list in subject_map.items():
            if subject == main_subject:
                continue
            if subject == city_served:
                for predicate, obj in triples_list:
                    if predicate == "country":
                        sentence += f", which is in {obj}"
                    elif predicate == "mayor":
                        sentence += f", where the mayor is {obj}"
                    elif predicate == "administrativeArrondissement":
                        sentence += f", part of the administrative arrondissement of {obj}"
                    elif predicate == "capital":
                        sentence += f", and {obj} is its capital"
                    elif predicate == "isPartOf":
                        sentence += f", and is part of {obj}"
                    elif predicate == "leader":
                        sentence += f", led by {obj}"
                    elif predicate == "language":
                        sentence += f", where the language is {obj}"

    # Handle country relationships for other entities
    for subject, triples_list in subject_map.items():
        if subject == main_subject or (city_served and subject == city_served):
            continue
        for predicate, obj in triples_list:
            if predicate == "country":
                sentence += f", and {subject} is in {obj}"
            elif predicate == "capital":
                sentence += f", and {obj} is the capital of {subject}"
            elif predicate == "officialLanguage":
                sentence += f", and {obj} is the official language of {subject}"

    return sentence + "."

